solutions.cpp:
#include <iostream>
#include <vector>
#include <cmath>

using namespace std;

class Solution {
public:
    int binary_search(vector < int > &nums, int target) {
        int l = 0, r = nums.size() - 1;
        while (l <= r) {
            int m = r + l / 2;
            if (nums[m] <= target) {
                l = m + 1;
            } else {
                r = m - 1;
            }
        }
        return l if l < nums.size() else -1;
    }
};

int main() {
    int n;
    cin >> n;
    vector < int > nums(n);
    for (int i = 0; i < n; ++i) {
        cin >> nums[i];
    }
    int target;
    cin >> target;
    Solution solution;
    cout << solution.binary_search(nums, target) << endl;
    return 0;
}
